-- ── State ─────────────────────────────────────────────────────────────────────
local reported         = {}     -- ap_id -> true once returned from poll()
local server_locations = nil    -- set of ap_ids the server expects (nil = all)
local rom_ok           = nil     -- cached OoS-cart result
local goal_option      = nil     -- slot_data goal (0/1), or nil = accept either
local mem              = {}
local log_fn           = nil

-- ── Logging ───────────────────────────────────────────────────────────────────
local function log(msg)
  if log_fn then pcall(log_fn, "[tloz_oos] " .. tostring(msg)) end
end

-- ── Memory API (resolved at init; 2-arg domain form + current-domain fallback) ─
local function resolve_memory_api()
  if not memory then return false end
  mem.read_u8 = memory.read_u8 or memory.readbyte
  return mem.read_u8 ~= nil
end

local function read_u8(addr, domain)
  if not mem.read_u8 then return nil end
  local ok, v = pcall(mem.read_u8, addr, domain)
  if ok and type(v) == "number" then return v end
  ok, v = pcall(mem.read_u8, addr)            -- older API: current domain
  if ok and type(v) == "number" then return v end
  return nil
end

local function bit_and(a, b)
  local res, bitval = 0, 1
  while a > 0 and b > 0 do
    if a % 2 == 1 and b % 2 == 1 then res = res + bitval end
    a = math.floor(a / 2); b = math.floor(b / 2); bitval = bitval * 2
  end
  return res
end

-- ── ROM identity: an Oracle of Seasons cart reads "ZELDA DIN" at header 0x0134.
--    (Ages reads "ZELDA NAYRU"; vanilla/garbage carts read neither.) Matches the
--    client's own validate_rom check exactly, so this self-disables on anything
--    that is not running Oracle of Seasons, never on a real OoS cart. ───────────
local function rom_is_ap()
  if rom_ok ~= nil then return rom_ok end
  for i = 1, #GAME_IDENT_STR do
    local b = read_u8(GAME_IDENT_ADDR + i - 1, ROM)
    if b == nil then return false end           -- not readable yet; retry next poll
    if b ~= string.byte(GAME_IDENT_STR, i) then
      rom_ok = false
      log("non-OoS ROM (no 'ZELDA DIN' at 0x0134) — detection idle")
      return false
    end
  end
  rom_ok = true
  log("Oracle of Seasons cart detected ('ZELDA DIN' at 0x0134) — detection live")
  return true
end

-- ── Multiworld context ────────────────────────────────────────────────────────
local function load_locations(ids)
  if type(ids) ~= "table" then return end
  server_locations = {}
  local n = 0
  for _, id in ipairs(ids) do
    local v = tonumber(id)
    if v then server_locations[v] = true; n = n + 1 end
  end
  log("server location set: " .. n .. " ids")
end

local function load_goal(slot_data)
  if type(slot_data) ~= "table" then return end
  -- slot_data may carry goal directly or nested under "options" (the world's
  -- on_package reads slot_data["options"]["goal"]). Accept either shape.
  local g = slot_data.goal
  if g == nil and type(slot_data.options) == "table" then g = slot_data.options.goal end
  local gv = tonumber(g)
  if gv ~= nil then
    goal_option = gv
    log("goal option = " .. tostring(gv) ..
        (gv == GOAL_BEAT_GANON and " (beat_ganon)" or " (beat_onox)"))
  end
end

local function wanted(ap_id)
  if server_locations == nil then return true end
  return server_locations[ap_id] == true
end

-- ── Detection gate (Client.py game_watcher: read_result[0][0] == 2) ───────────
local function in_gameplay()
  local s = read_u8(GAME_STATE_ADDR, SYSBUS)
  return s ~= nil and s == GAME_STATE_INGAME
end

-- ── Per-flag evaluation: (byte & mask) == mask  (note equality) ───────────────
local function flag_done(entry)
  local b = read_u8(entry.a, SYSBUS)
  if b == nil then return false end
  return bit_and(b, entry.m) == entry.m
end

local function current_room()
  local hi = read_u8(MAP_GROUP_ADDR, SYSBUS)
  local lo = read_u8(MAP_ID_ADDR, SYSBUS)
  if hi == nil or lo == nil then return nil end
  return hi * 0x100 + lo
end

-- ── Module contract ───────────────────────────────────────────────────────────
function M.init(ctx)
  if ctx and type(ctx.log) == "function" then log_fn = ctx.log end
  if not resolve_memory_api() then
    log("BizHawk memory API unavailable — module idle")
    ADDRESSES_VERIFIED = false
    return
  end
  local cfg = (ctx and ctx.config) or {}
  load_locations(cfg.locations)
  load_goal(cfg.slot_data)
  local n = 0; for _ in pairs(LOC) do n = n + 1 end
  log("ready: " .. n .. " flag locations + " .. #GASHA_IDS ..
      " gasha (0x" .. string.format("%04X", FLAGS_LOW) ..
      "..0x" .. string.format("%04X", FLAGS_HIGH) .. ")")
end

function M.poll()
  local new = {}
  if not ADDRESSES_VERIFIED then return new end
  if not rom_is_ap() then return new end
  if not in_gameplay() then return new end

  -- Flag-bit locations.
  for ap_id, entry in pairs(LOC) do
    if not reported[ap_id] and wanted(ap_id) and flag_done(entry) then
      reported[ap_id] = true
      new[#new + 1] = ap_id
    end
  end

  -- Deterministic Gasha Nuts: first `count` ids, count = byte(0xC649) >> 2.
  local gc = read_u8(GASHA_COUNTER_ADDR, SYSBUS)
  if gc ~= nil then
    local count = math.floor(gc / 4)
    if count > #GASHA_IDS then count = #GASHA_IDS end
    for i = 1, count do
      local ap_id = GASHA_IDS[i]
      if not reported[ap_id] and wanted(ap_id) then
        reported[ap_id] = true
        new[#new + 1] = ap_id
      end
    end
  end

  return new
end

function M.is_goal_complete()
  if not ADDRESSES_VERIFIED or not rom_is_ap() then return false end
  if not in_gameplay() then return false end
  local room = current_room()
  if room == nil then return false end

  -- beat_onox: reached the room with Din's descending crystal.
  local onox_done = (room == ROOM_AFTER_DRAGONOX)
  -- beat_ganon: reached Zelda's ending room AND Ganon flag set.
  local ganon_done = false
  if room == ROOM_ZELDA_ENDING then
    local f = read_u8(GANON_FLAG_ADDR, SYSBUS)
    ganon_done = (f ~= nil and bit_and(f, GANON_FLAG_MASK) == GANON_FLAG_MASK)
  end

  if goal_option == GOAL_BEAT_ONOX then
    return onox_done
  elseif goal_option == GOAL_BEAT_GANON then
    return ganon_done
  end
  -- Unknown goal (no slot_data): accept either end-of-game condition. Neither
  -- can false-positive — both are terminal rooms.
  return onox_done or ganon_done
end

-- Remote multiworld items: see the file header. OoS items_handling = 0b001 means
-- the patched game grants its own found items, so solo play and check reporting
-- work fully; delivering REMOTE items is the client's guarded write handshake
-- (poll the received-item index at 0xC6A0, write id/subid into the struct at
-- 0xCBFB only when empty and not inside Blaino's Gym). That write path is the one
-- piece deferred until it can be confirmed in-emulator. No-op (never a wrong
-- write) until then.
function M.receive_item(item_id, meta)
  -- intentionally empty (documented)
end

return M
